private String pad(String str, int size) {
    if (str == null) str = "";
    int len = 0;
    for (char c : str.toCharArray()) {
        len += (c > 127) ? 2 : 1;  // 한글=2칸, 영문=1칸
    }
    int padSize = size - len;
    if (padSize <= 0) return str;
    return str + " ".repeat(padSize);
}
